const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const monthAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
const weekStart = weekAgo.toISOString();
const monthStart = monthAgo.toISOString();
const today = now.toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
return [{ json: { weekStart, monthStart, today } }];

const leadsData = $('📋 Leads esta semana').all();
const leads = Array.isArray(leadsData[0]?.json) ? leadsData[0].json : leadsData.map(i => i.json);
const totalPendientes = $('🔢 Total leads pendientes').first()?.json?.length ?? 0;
const today = $('📅 Calcular fechas').first().json.today;

const nuevos = leads.length;
const ciudades = [...new Set(leads.map(l => l.city).filter(Boolean))].slice(0, 5).join(', ') || '—';
const intereses = leads.map(l => l.interest).filter(Boolean);
const interesTop = intereses.length > 0
  ? [...intereses.reduce((acc, i) => { acc.set(i, (acc.get(i) || 0) + 1); return acc; }, new Map())].sort((a,b) => b[1]-a[1])[0][0]
  : '—';

const resumen = leads.slice(0, 5).map(l =>
  `  • ${l.business_name || l.contact_name || '?'} (${l.city || '—'})`
).join('\n');

const mensaje = [
  `📊 *REPORTE SEMANAL — BarberíaOS*`,
  `📅 ${today}`,
  '',
  `🔔 *Leads nuevos esta semana:* ${nuevos}`,
  `📍 *Ciudades:* ${ciudades}`,
  `💡 *Interés más frecuente:* ${interesTop}`,
  '',
  nuevos > 0 ? `*Últimos leads:*\n${resumen}` : '_Sin leads nuevos esta semana._',
  '',
  `📋 *En CRM sin contactar:* ${totalPendientes}`,
  '',
  nuevos > 0 ? '⚡ Contacta hoy para no perder el interés.' : '🎯 Semana tranquila — buen momento para crear contenido.',
  '',
  `🔗 https://barberiaos.com/admin/leads`
].join('\n');

return [{ json: { mensaje } }];
